SELECT 
  FROM er.tn_eucr_batch b
 WHERE b.eucr_id  = #{eucrId}
   AND b.batch_no = #{batchNo}
   AND NOW() BETWEEN b.use_bgng_dt AND b.use_end_dt

SELECT CASE WHEN COUNT(*) > 0 THEN TRUE ELSE FALSE END
  FROM er.tn_eucr_batch
 WHERE eucr_id  = #{eucrId}
   AND batch_no = #{batchNo}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

mapper.update:
UPDATE er.tn_eucr_batch
   SET use_end_dt       = NOW() - INTERVAL '1 minute',
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE eucr_id  = #{eucrId}
   AND batch_no = #{batchNo}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
